const API_BASE = "http://localhost:3300";

// ─── VEHICLES ────────────────────────────────────────────────────────────────
export async function getVehicles() {
  const res = await fetch(`${API_BASE}/vehicles`);
  if (!res.ok) throw new Error("Erro ao buscar veículos");
  return res.json();
}

export async function getVehicleById(id) {
  const res = await fetch(`${API_BASE}/vehicles/${id}`);
  if (!res.ok) throw new Error("Veículo não encontrado");
  return res.json();
}

export async function createVehicle(data) {
  const res = await fetch(`${API_BASE}/vehicles`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

export async function updateVehicle(id, data) {
  const res = await fetch(`${API_BASE}/vehicles/${id}`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

export async function deleteVehicle(id) {
  await fetch(`${API_BASE}/vehicles/${id}`, { method: "DELETE" });
}

// ─── USERS ───────────────────────────────────────────────────────────────────
export async function createUser(data) {
  const res = await fetch(`${API_BASE}/users`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) throw new Error("Erro ao criar usuário");
  return res.json();
}

export async function getAllUsers() {
  const res = await fetch(`${API_BASE}/users`);
  return res.json();
}

export async function getUserById(id) {
  const res = await fetch(`${API_BASE}/users/${id}`);
  return res.json();
}

export async function updateUser(id, data) {
  const res = await fetch(`${API_BASE}/users/${id}`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

export async function deleteUser(id) {
  await fetch(`${API_BASE}/users/${id}`, { method: "DELETE" });
}

// ─── PROPOSALS ───────────────────────────────────────────────────────────────
export async function createProposal(data) {
  const res = await fetch(`${API_BASE}/proposals`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) throw new Error("Erro ao enviar proposta");
  return res.json();
}

export async function getProposalsByVehicle(vehicleId) {
  const res = await fetch(`${API_BASE}/proposals/vehicle/${vehicleId}`);
  return res.json();
}

export async function updateProposalStatus(id, status) {
  const res = await fetch(`${API_BASE}/proposals/${id}/status`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ status }),
  });
  return res.json();
}

// ─── REVIEWS ─────────────────────────────────────────────────────────────────
export async function createReview(data) {
  const res = await fetch(`${API_BASE}/reviews`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

export async function getReviewsByUser(userId) {
  const res = await fetch(`${API_BASE}/reviews/user/${userId}`);
  return res.json();
}

// ─── VEHICLE IMAGES ──────────────────────────────────────────────────────────
export async function addVehicleImage(data) {
  const res = await fetch(`${API_BASE}/images`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

export async function deleteVehicleImage(id) {
  await fetch(`${API_BASE}/images/${id}`, { method: "DELETE" });
}

// ─── HELPER ──────────────────────────────────────────────────────────────────
export function getImageUrl(filename) {
  return `${API_BASE}/uploads/${filename}`;
}
